import React, { useState } from 'react';
import {
  View,
  Text,
  ScrollView,
  StyleSheet,
  TouchableOpacity,
  Dimensions,
  Linking,
} from 'react-native';
import {
  SafeAreaContainer,
  Header,
  EmergencyButton,
  BottomTabs,
  OfflineDot,
  SafeArrivalBanner,
  Colors,
  SCREEN_WIDTH,
} from '../components/Layout';
import { useIncidentStore } from '../store';

const COL_GAP = 12;
const SIDE_PAD = 16;
const FULL_BTN_W = SCREEN_WIDTH - SIDE_PAD * 2;
const HALF_BTN_W = (SCREEN_WIDTH - SIDE_PAD * 2 - COL_GAP) / 2;

export const HomeScreen: React.FC<{ navigation: any }> = ({ navigation }) => {
  const [activeTab, setActiveTab] = useState('home');
  const { userName, offlineStatus, safeArrival, clearSafeArrival } = useIncidentStore();

  const nav = (screen: string, params?: any) =>
    navigation.navigate('EmergencyFlows', { screen, params });

  const navSupport = (screen: string) =>
    navigation.navigate('SupportFlows', { screen });

  const tabs = [
    { id: 'home',    icon: '🏠', label: 'Home',      action: () => setActiveTab('home') },
    { id: 'profile', icon: '👤', label: 'Profile',   action: () => setActiveTab('profile') },
    { id: 'qr',      icon: '🆔', label: 'Medical ID', action: () => navSupport('MedicalID') },
    { id: 'arrival', icon: '🛣', label: 'Safe Drive',  action: () => navSupport('SafeArrival') },
  ];

  return (
    <SafeAreaContainer style={{ flex: 1 }}>
      {/* Top Bar */}
      <View style={ss.topBar}>
        <Text style={ss.logo}>🚨 ROADSoS</Text>
        <OfflineDot status={offlineStatus} />
        <TouchableOpacity onPress={() => setActiveTab('profile')} style={ss.profileIcon}>
          <Text style={{ fontSize: 22 }}>👤</Text>
        </TouchableOpacity>
      </View>

      {/* Safe Arrival Banner */}
      {safeArrival.deadline && (
        <SafeArrivalBanner
          destination={safeArrival.destination}
          deadline={safeArrival.deadline}
          onCheckIn={clearSafeArrival}
        />
      )}

      <ScrollView contentContainerStyle={ss.content} showsVerticalScrollIndicator={false}>
        {activeTab === 'home' && (
          <>
            <Text style={ss.heading}>What's the emergency?</Text>

            {/* Row 1: Accident/Crash — full width, large */}
            <View style={ss.row}>
              <View style={{ width: FULL_BTN_W }}>
                <EmergencyButton
                  icon="🚗"
                  title="Accident / Crash"
                  color={Colors.red}
                  onPress={() => nav('Triage')}
                  size="large"
                />
              </View>
            </View>

            {/* Row 2: Car Fire — full width, large */}
            <View style={[ss.row, { marginTop: COL_GAP }]}>
              <View style={{ width: FULL_BTN_W }}>
                <EmergencyButton
                  icon="🔥"
                  title="Car Fire"
                  color={Colors.orange}
                  onPress={() => nav('EvacuationGuide')}
                  size="large"
                />
              </View>
            </View>

            {/* Row 3: 4 medium buttons in 2×2 grid */}
            <View style={[ss.grid, { marginTop: COL_GAP }]}>
              <View style={{ width: HALF_BTN_W }}>
                <EmergencyButton icon="🔧" title="Breakdown" color={Colors.blue} onPress={() => nav('EmergencyBreakdown', { defaultTab: 0 })} />
              </View>
              <View style={{ width: HALF_BTN_W }}>
                <EmergencyButton icon="⛽" title="Out of Fuel" color={Colors.purple} onPress={() => nav('EmergencyBreakdown', { defaultTab: 2 })} />
              </View>
              <View style={{ width: HALF_BTN_W, marginTop: COL_GAP }}>
                <EmergencyButton icon="🌊" title="Flood / Natural" color={Colors.teal} onPress={() => nav('EmergencyFlood')} />
              </View>
              <View style={{ width: HALF_BTN_W, marginTop: COL_GAP }}>
                <EmergencyButton icon="🚨" title="Crime / Theft" color={Colors.slate} onPress={() => nav('EmergencySOS')} />
              </View>
            </View>

            {/* Bystander ghost strip */}
            <TouchableOpacity
              style={ss.bystanderStrip}
              onPress={() => navSupport('BystanderEntry')}
            >
              <Text style={ss.bystanderText}>👁 I'm a bystander — help someone nearby</Text>
            </TouchableOpacity>
          </>
        )}

        {activeTab === 'profile' && <ProfileTab navigation={navigation} />}
      </ScrollView>

      <BottomTabs activeTab={activeTab} tabs={tabs} />
    </SafeAreaContainer>
  );
};

// ─── PROFILE TAB ─────────────────────────────────────────────────────────────
const ProfileTab: React.FC<{ navigation: any }> = ({ navigation }) => {
  const { userName, userPhone, emergencyContacts, medicalDetails, language } = useIncidentStore();

  const navSupport = (screen: string) =>
    navigation.navigate('SupportFlows', { screen });

  return (
    <ScrollView showsVerticalScrollIndicator={false}>
      {/* Personal */}
      <View style={ss.profileCard}>
        <Text style={ss.profileCardTitle}>👤 Personal Info</Text>
        <Row label="Name" value={userName || 'Not set'} />
        <Row label="Phone" value={userPhone || 'Not set'} />
        <Row label="Language" value={{ en: 'English', hi: 'हिंदी', gu: 'ગુજરાતી' }[language]} />
      </View>

      {/* Emergency Contacts */}
      <View style={ss.profileCard}>
        <Text style={ss.profileCardTitle}>🆘 Emergency Contacts</Text>
        {emergencyContacts.length === 0 ? (
          <Text style={ss.emptyText}>No contacts saved</Text>
        ) : (
          emergencyContacts.map((c, i) => (
            <Row key={i} label={`Contact ${i + 1}`} value={`${c.name} · ${c.phone}`} />
          ))
        )}
      </View>

      {/* Medical */}
      <View style={ss.profileCard}>
        <Text style={ss.profileCardTitle}>🩸 Medical Info</Text>
        <Row label="Blood Group" value={medicalDetails.bloodGroup || 'Not set'} />
        <Row label="Allergies" value={medicalDetails.allergies || 'None'} />
        <Row label="Medications" value={medicalDetails.medications || 'None'} />
      </View>

      {/* Quick links */}
      <TouchableOpacity style={ss.profileLink} onPress={() => navigation.navigate('SupportFlows', { screen: 'SafeArrival' })}>
        <Text style={ss.profileLinkText}>🛣 Set Safe Arrival Alert</Text>
        <Text style={ss.profileLinkArrow}>›</Text>
      </TouchableOpacity>
      <TouchableOpacity style={ss.profileLink} onPress={() => navigation.navigate('SupportFlows', { screen: 'MedicalID' })}>
        <Text style={ss.profileLinkText}>🆔 View Medical QR ID</Text>
        <Text style={ss.profileLinkArrow}>›</Text>
      </TouchableOpacity>
      <TouchableOpacity
        style={[ss.profileLink, { marginBottom: 32 }]}
        onPress={() => navigation.navigate('SupportFlows', { screen: 'BystanderEntry' })}
      >
        <Text style={ss.profileLinkText}>👁 I'm a Bystander</Text>
        <Text style={ss.profileLinkArrow}>›</Text>
      </TouchableOpacity>

      <TouchableOpacity
        style={ss.editProfileBtn}
        onPress={() => navigation.navigate('Setup')}
      >
        <Text style={ss.editProfileText}>✏️ Edit Profile</Text>
      </TouchableOpacity>
    </ScrollView>
  );
};

const Row: React.FC<{ label: string; value: string }> = ({ label, value }) => (
  <View style={ss.profileRow}>
    <Text style={ss.profileRowLabel}>{label}</Text>
    <Text style={ss.profileRowValue}>{value}</Text>
  </View>
);

// ─── STYLES ──────────────────────────────────────────────────────────────────
const ss = StyleSheet.create({
  topBar: {
    flexDirection: 'row', alignItems: 'center', justifyContent: 'space-between',
    paddingHorizontal: 16, paddingVertical: 12,
    borderBottomWidth: 1, borderBottomColor: Colors.gray200,
    backgroundColor: '#fff',
  },
  logo: { fontSize: 18, fontWeight: '900', color: Colors.gray900 },
  profileIcon: { padding: 4 },
  content: { paddingHorizontal: SIDE_PAD, paddingTop: 20, paddingBottom: 100 },

  heading: { fontSize: 26, fontWeight: '800', color: Colors.gray900, marginBottom: 16 },
  row: { flexDirection: 'row' },
  grid: { flexDirection: 'row', flexWrap: 'wrap', justifyContent: 'space-between' },

  bystanderStrip: {
    marginTop: 20, borderWidth: 1.5, borderColor: Colors.green,
    borderRadius: 12, paddingVertical: 14, alignItems: 'center',
    backgroundColor: '#f0fdf4',
  },
  bystanderText: { color: Colors.greenDark, fontWeight: '700', fontSize: 15 },

  profileCard: {
    backgroundColor: '#fff', borderRadius: 14, borderWidth: 1,
    borderColor: Colors.gray200, padding: 16, marginBottom: 12,
    elevation: 1, shadowColor: '#000', shadowOffset: { width: 0, height: 1 },
    shadowOpacity: 0.04, shadowRadius: 2,
  },
  profileCardTitle: { fontSize: 15, fontWeight: '800', color: Colors.gray900, marginBottom: 12 },
  profileRow: { flexDirection: 'row', justifyContent: 'space-between', paddingVertical: 6, borderBottomWidth: 1, borderBottomColor: Colors.gray100 },
  profileRowLabel: { fontSize: 13, color: Colors.gray500 },
  profileRowValue: { fontSize: 13, color: Colors.gray900, fontWeight: '600', flexShrink: 1, textAlign: 'right', maxWidth: '60%' },
  emptyText: { fontSize: 13, color: Colors.gray400, fontStyle: 'italic' },

  profileLink: {
    flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center',
    backgroundColor: '#fff', borderRadius: 12, padding: 16,
    marginBottom: 8, borderWidth: 1, borderColor: Colors.gray200,
  },
  profileLinkText: { fontSize: 15, fontWeight: '600', color: Colors.gray800 },
  profileLinkArrow: { fontSize: 20, color: Colors.gray400 },

  editProfileBtn: {
    backgroundColor: Colors.gray100, borderRadius: 12, paddingVertical: 14,
    alignItems: 'center', marginBottom: 16,
  },
  editProfileText: { fontSize: 15, fontWeight: '700', color: Colors.gray800 },
});
